@Composable
fun Counter() {
    var count by remember { mutableIntStateOf(0) }
    Button(onClick = { count++ }) {
        Text("Count: $count")
    }
}

@Composable
fun NameField(value: String, onValueChange: (String) -> Unit, error: String?) {
    Column {
        OutlinedTextField(value, onValueChange, isError = error != null)
        error?.let { Text(it) }
    }
}

@Composable
fun ProfileEditor() {
    var name by rememberSaveable { mutableStateOf("") }
    val error = name.takeIf { it.length > 50 }?.let { "Tối đa 50 ký tự" }
    NameField(name, { name = it }, error)
}

private val _state = MutableStateFlow(EditorUiState())

fun onTitleChanged(value: String) {
    _state.update { current -> current.copy(title = value, titleError = null) }
}

// Không an toàn nếu hai coroutine cùng chạy
val old = _state.value
_state.value = old.copy(loading = true)

// Ưu tiên atomic transform
_state.update { it.copy(loading = true) }

sealed interface LoginAction {
    data class EmailChanged(val value: String) : LoginAction
    data object Submit : LoginAction
}

fun reduce(state: LoginUiState, action: LoginAction): LoginUiState = when (action) {
    is LoginAction.EmailChanged -> state.copy(email = action.value, emailError = null)
    LoginAction.Submit -> state.copy(loading = true)
}
